// TestComputeBillingFingerprint_KnownVectors pins the SHA256-based fingerprint
// algorithm to byte-exact expected values. These vectors were generated by a
// standalone Go program using the documented algorithm:
//
//	SHA256("59cf53e54c78" + msg[4] + msg[7] + msg[20] + version)[:3]
//
// with out-of-range indices substituted with '0'. If upstream ever changes
// the salt, indices, or hash digest, these tests will fail loudly. Any
// change must be cross-checked against real Claude CLI traffic AND the
// auth2api reference (../auth2api/src/proxy/cloaking.ts:computeFingerprint).
func TestComputeBillingFingerprint_KnownVectors(t *testing.T) {
	t.Parallel()
	cases := []struct {
		name    string
		msg     string
		version string
		want    string
	}{
		// msg shorter than max index (20) → all three chars are '0'.
		{"empty message 2.1.88", "", "2.1.88", "758"},
		{"empty message 2.1.76", "", "2.1.76", "4dc"},
		{"short message 2.1.88", "hi", "2.1.88", "758"},
		// Long enough to cover all three indices (4=o, 7=w, 20=t).
		{"long message 2.1.88", "Hello, world! This is a test message.", "2.1.88", "e72"},
	}
	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			got := computeBillingFingerprint(tc.msg, tc.version)
			if got != tc.want {
				t.Errorf("computeBillingFingerprint(%q, %q) = %q, want %q",
					tc.msg, tc.version, got, tc.want)
			}
		})
	}
}

func TestExtractFirstUserMessageText(t *testing.T) {
	t.Parallel()
	cases := []struct {
		name string
		body string
		want string
	}{
		{
			name: "string content",
			body: `{"messages":[{"role":"user","content":"hello there"}]}`,
			want: "hello there",
		},
		{
			name: "array with text block",
			body: `{"messages":[{"role":"user","content":[{"type":"text","text":"block text"}]}]}`,
			want: "block text",
		},
		{
			name: "array with non-text block first",
			body: `{"messages":[{"role":"user","content":[{"type":"image"},{"type":"text","text":"t"}]}]}`,
			want: "t",
		},
		{
			name: "assistant before user",
			body: `{"messages":[{"role":"assistant","content":"ai"},{"role":"user","content":"human"}]}`,
			want: "human",
		},
		{
			name: "no user message",
			body: `{"messages":[{"role":"assistant","content":"ai"}]}`,
			want: "",
		},
		{
			name: "no messages field",
			body: `{}`,
			want: "",
		},
	}
	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			parsed := parseJSON(t, tc.body)
			got := extractFirstUserMessageText(parsed)
			if got != tc.want {
				t.Errorf("extractFirstUserMessageText = %q, want %q", got, tc.want)
			}
		})
	}
}

// expectedSuffix is the fingerprint for an empty user message at version
// 2.1.88 — the value used by tests that don't supply messages.
const expectedSuffix2_1_88EmptyMsg = "758"

func TestSyncBillingHeaderVersion_ArraySystemRecomputesSuffix(t *testing.T) {
	t.Parallel()
	// Note: no "messages" field → extractFirstUserMessageText returns "" →
	// suffix computed from empty chars + version "2.1.88" = "758".
	// The OLD ".df2" suffix must be REPLACED, not preserved.
	parsed := parseJSON(t, `{
		"system": [
			{"type":"text","text":"x-anthropic-billing-header: cc_version=2.1.76.df2; cc_entrypoint=cli; cch=abc12"},
			{"type":"text","text":"You are Claude Code."}
		],
		"messages":[]
	}`)

	syncBillingHeaderVersion(parsed, "2.1.88")

	sys := parsed["system"].([]interface{})
	got := sys[0].(map[string]interface{})["text"].(string)
	want := "x-anthropic-billing-header: cc_version=2.1.88." + expectedSuffix2_1_88EmptyMsg + "; cc_entrypoint=cli; cch=abc12"
	if got != want {
		t.Errorf("expected %q, got %q", want, got)
	}
	// Non-billing block must be untouched.
	other := sys[1].(map[string]interface{})["text"].(string)
	if other != "You are Claude Code." {
		t.Errorf("non-billing block was mutated: %q", other)
	}
}

func TestSyncBillingHeaderVersion_NoSuffix_AppendsSuffix(t *testing.T) {
	t.Parallel()
	// Client sent a suffix-less cc_version. After sync, the suffix must be
	// appended so the output is always fully-qualified.
	parsed := parseJSON(t, `{
		"system": [
			{"type":"text","text":"x-anthropic-billing-header: cc_version=2.1.76; cc_entrypoint=cli;"}
		]
	}`)

	syncBillingHeaderVersion(parsed, "2.1.88")

	sys := parsed["system"].([]interface{})
	got := sys[0].(map[string]interface{})["text"].(string)
	want := "x-anthropic-billing-header: cc_version=2.1.88." + expectedSuffix2_1_88EmptyMsg + "; cc_entrypoint=cli;"
	if got != want {
		t.Errorf("expected %q, got %q", want, got)
	}
}

