func TestSyncBillingHeaderVersion_NonBillingStringIsUntouched(t *testing.T) {
	t.Parallel()
	parsed := parseJSON(t, `{
		"system": "You are Claude Code. cc_version=2.1.76 appears in user text."
	}`)
	original := parsed["system"].(string)

	syncBillingHeaderVersion(parsed, "2.1.88")

	got := parsed["system"].(string)
	if got != original {
		t.Errorf("non-billing string system was mutated: %q -> %q", original, got)
	}
}

func TestSyncBillingHeaderVersion_NoBillingBlock(t *testing.T) {
	t.Parallel()
	parsed := parseJSON(t, `{
		"system": [
			{"type":"text","text":"You are Claude Code, Anthropic's official CLI for Claude."}
		]
	}`)

	before, _ := json.Marshal(parsed)
	syncBillingHeaderVersion(parsed, "2.1.88")
	after, _ := json.Marshal(parsed)

	if string(before) != string(after) {
		t.Errorf("expected no change, got before=%s after=%s", before, after)
	}
}

